on conflict (source_url) do update set
  activity_name = excluded.activity_name,
  address = excluded.address,
  postcode = excluded.postcode,
  category = excluded.category,
  start_time = excluded.start_time,
  end_time = excluded.end_time,
  google_link = excluded.google_link,
  website = excluded.website,
  child_friendly_score = excluded.child_friendly_score,
  age_suitability = excluded.age_suitability,
  borough = excluded.borough,
  days_of_week = excluded.days_of_week,
  recurrence_rule = excluded.recurrence_rule,
  schedule_notes = excluded.schedule_notes,
  description = excluded.description,
  cost = excluded.cost,
  booking_required = excluded.booking_required,
  source_name = excluded.source_name,
  image_url = coalesce(excluded.image_url, public.activities.image_url),
  image_source_url = coalesce(excluded.image_source_url, public.activities.image_source_url),
  activity_date = excluded.activity_date,
  available_dates = excluded.available_dates,
  available_days_of_week = excluded.available_days_of_week,
  availability_type = excluded.availability_type,
  availability_notes = excluded.availability_notes,
  public_listing_status = 'published',
  updated_at = now();

select count(*) as happity_waltham_forest_live_listings, count(image_url) as listings_with_happity_images
from public.activities
where source_name = 'Happity'
  and borough = 'Waltham Forest'
  and source_url like 'https://www.happity.co.uk/schedules/%';
